بخش ۳: انواع داده - اطلاعاتی که ذخیره می‌کنیم
۱. رشته (String) - برای متن‌ها
let name = &quot;سارا&quot;;
let message = &#039;سلام دنیا!&#039;;
let template = `سلام ${name}`; // روش جدید با قابلیت قراردادن متغیر
متدهای مفید رشته:
let text = &quot;  JavaScript  &quot;;

console.log(text.length); // 13 (طول رشته)
console.log(text.trim()); // &quot;JavaScript&quot; (حذف فضاهای اضافه)
console.log(text.toUpperCase()); // &quot;  JAVASCRIPT  &quot;
console.log(text.toLowerCase()); // &quot;  javascript  &quot;
console.log(text.includes(&quot;Java&quot;)); // true
console.log(text.slice(2, 6)); // &quot;Java&quot; (برش رشته)
۲. عدد (Number) - برای محاسبات
let integer = 42;      // عدد صحیح
let decimal = 3.14;    // عدد اعشاری
let negative = -10;    // عدد منفی
متدهای مفید عدد:
let num = 123.456;

console.log(num.toFixed(2)); // &quot;123.46&quot; (گرد کردن)
console.log(num.toString()); // &quot;123.456&quot; (تبدیل به رشته)

// تبدیل رشته به عدد
console.log(parseInt(&quot;100px&quot;)); // 100
console.log(parseFloat(&quot;3.14cm&quot;)); // 3.14
مقادیر خاص:
console.log(1 / 0);        // Infinity
console.log(-1 / 0);       // -Infinity  
console.log(&quot;text&quot; * 2);   // NaN (Not a Number)
۳. بولین (Boolean) - درست یا غلط
let isActive = true;
let isEmpty = false;
مقادیر truthy و falsy:

falsy values: false, 0, &quot;&quot;, null, undefined, NaN
بقیه مقادیر truthy هستند (حتی &quot;0&quot;, &quot;false&quot;, [], {})

// مثال‌های کاربردی
if (&quot;&quot;) {
    console.log(&quot;این اجرا نمی‌شود&quot;); // &quot;&quot; falsy است
}

if (&quot;سلام&quot;) {
    console.log(&quot;این اجرا می‌شود&quot;); // هر رشته غیرخالی truthy است
}

if (0) {
    console.log(&quot;این اجرا نمی‌شود&quot;); // 0 falsy است
}

سؤالات تمرینی بخش ۳:
۱. خروجی کد زیر چیست؟
let price = &quot;200&quot;;
let tax = &quot;20&quot;;
console.log(price + tax);
console.log(parseInt(price) + parseInt(tax));
۲. کدام عبارت‌های زیر true برمی‌گردانند؟
Boolean(&quot;&quot;)           // اول
Boolean(&quot;0&quot;)          // دوم  
Boolean(0)            // سوم
Boolean([])           // چهارم
۳. مشکل کد زیر چیست؟ چگونه اصلاح می‌شود؟
let userAge = &quot;25سال&quot;;
let ageAfter5Years = userAge.toFixed() + 5;

بررسی پاسخ‌های بخش ۳:
**پاسخ ۱:

خط اول: &quot;200&quot; + &quot;20&quot; = &quot;20020&quot; وقتی با + دو رشته را جمع کنیم، آنها به هم وصل می‌شوند (concatenate)
خط دوم: 200 + 20 = 220

**پاسخ ۲:

Boolean(&quot;&quot;) = false (رشته خالی falsy است)
Boolean(&quot;0&quot;) = true (هر رشته غیرخالی truthy است)
Boolean(0) = false (عدد صفر falsy است)
Boolean([]) = true (آرایه خالی هم truthy است)

**پاسخ ۳:

toFixed() روی رشته کار نمی‌کند
parseInt(userAge).toFixed() + 5
نتیجه نهایی &quot;25&quot; + 5 = &quot;255&quot; می‌شود! چون toFixed() یک رشته برمی‌گرداند

راه حل بهتر:
let userAge = &quot;25سال&quot;;
let ageAfter5Years = parseInt(userAge) + 5; // عدد 30
// یا اگر حتماً نیاز به toFixed داریم:
let ageAfter5Years = (parseInt(userAge) + 5).toFixed(); // رشته &quot;30&quot;

نکات مهمی که یاد گرفتیم:

+ با رشته‌ها: وقتی حداقل یکی از operandها رشته باشد، + عمل concatenation انجام می‌دهد
تبدیل نوع: همیشه مراقب باشیم چه نوع داده‌ای داریم و چه متدهایی روی آن کار می‌کند
truthy/falsy: آرایه خالی [] truthy است اما رشته خالی &quot;&quot; falsy است


حتماً! با کمال میل. بیا دقیقاً بر اساس متن اصلی که ارائه کردی پیش بریم.

بخش ۴: عملگرها - ریاضی، مقایسه و منطق (مطابق متن اصلی)
۱. عملگرهای حسابی (Arithmetic Operators)
برای انجام عملیات ریاضی استفاده می‌شوند:





















































عملگرتوضیحمثالنتیجه+جمع5 + 611-تفریق10 - 82*ضرب5 * 420/تقسیم20 / 54%باقیمانده7 % 31++افزایشlet a = 2; a++a = 3--کاهشlet b = 5; b--b = 4
مثال از متن:
let x1 = 10, y1 = 4;

console.log(x1 + y1); // 14
console.log(x1 - y1); // 6
console.log(x1 * y1); // 40
console.log(x1 / y1); // 2.5
console.log(x1 % y1); // 2

let a = 5;
a++;
console.log(a); // 6
let b = 10;
b--;
console.log(b); // 9
۲. عملگرهای مقایسه‌ای (Comparison Operators)
دو مقدار را با هم مقایسه می‌کنند و true یا false برمی‌گردانند:



























































عملگرتوضیحمثالنتیجه==برابر (با تبدیل نوع)5 == &#039;5&#039;true===برابر دقیق (بدون تبدیل نوع)5 === &#039;5&#039;false!=نامساوی (با تبدیل نوع)5 != &#039;5&#039;false!==نامساوی دقیق (بدون تبدیل نوع)5 !== &#039;5&#039;true&gt;بزرگتر از10 &gt; 5true&lt;کوچکتر از10 &lt; 5false&gt;=بزرگتر یا مساوی10 &gt;= 10true&lt;=کوچکتر یا مساوی10 &lt;= 5false
مثال از متن:
let num1 = 10, num2 = 5, num3 = &quot;10&quot;;
console.log(num1 == num3);  // true (مقادیر یکسان پس از تبدیل نوع)
console.log(num1 === num3); // false (نوع‌ها متفاوت است)
console.log(num1 &gt; num2);   // true
console.log(num1 &lt;= num2);  // false
console.log(num1 !== num3); // true (مقادیر یا نوع‌ها متفاوت است)
۳. عملگرهای منطقی (Logical Operators)
برای ترکیب چند شرط استفاده می‌شوند:





























عملگرتوضیحمثالنتیجه&amp;&amp;AND (هر دو باید true باشند)true &amp;&amp; falsefalse||OR (یکی باید true باشد)true || falsetrue!NOT (برعکس می‌کند)!truefalse
مثال از متن:
let a = 10, b = 5, c = 15;

// AND منطقی
if (a &gt; b &amp;&amp; c &gt; a) {
    console.log(&quot;هر دو شرط true هستند.&quot;);
} else {
    console.log(&quot;حداقل یکی از شرط‌ها false است.&quot;);
}
// خروجی: &quot;هر دو شرط true هستند.&quot;

// OR منطقی
if (a &lt; b || c &gt; a) {
    console.log(&quot;حداقل یکی از شرط‌ها true است.&quot;);
}
// خروجی: &quot;حداقل یکی از شرط‌ها true است.&quot;

// NOT منطقی
let isLoggedIn = false;
if (!isLoggedIn) {
    console.log(&quot;کارگر وارد سیستم نیست.&quot;);
}
// خروجی: &quot;کارگر وارد سیستم نیست.&quot;
۴. اولویت عملگرها (Operator Precedence)
تعیین می‌کند کدام عملگر زودتر اجرا شود:

() بالاترین اولویت را دارد
* و / قبل از + و - اجرا می‌شوند
&amp;&amp; قبل از || اجرا می‌شود

مثال از متن:
let result = 10 + 5 * 2; // ضرب اولویت دارد
console.log(result); // 20

let result2 = (10 + 5) * 2; // پرانتز اولویت دارد
console.log(result2); // 30

سؤالات تمرینی بخش ۴ (مطابق متن اصلی):
۱. خروجی کد زیر چیست؟
let num = 7;
console.log(num++ + ++num);
۲. کدام یک از عبارات زیر true برمی‌گرداند؟
5 == &quot;5&quot;     // اول
5 === &quot;5&quot;    // دوم  
&quot;&quot; == false  // سوم
0 == false   // چهارم
۳. با استفاده از عملگرهای منطقی، شرطی بنویس که بررسی کند:

یک عدد بین ۱۸ تا ۶۰ است (شامل خود ۱۸ و ۶۰ باشد)
یا اینکه عدد دقیقاً برابر ۱۶ باشد

بررسی پاسخ‌های بخش ۴:
**پاسخ ۱:

این سؤال نیاز به دقت بیشتری دارد. بیا مرحله به مرحله محاسبه کنیم:
let num = 7;
// num++ : مقدار فعلی (7) استفاده می‌شود، سپس num به 8 افزایش می‌یابد
// ++num : ابتدا num از 8 به 9 افزایش می‌یابد، سپس مقدار جدید (9) استفاده می‌شود
// بنابراین: 7 + 9 = 16

پاسخ صحیح: 16

**پاسخ ۲:

5 == &quot;5&quot; → true (مقادیر پس از تبدیل نوع برابرند)
5 === &quot;5&quot; → false (مقادیر برابر ولی نوع‌ها متفاوت)
&quot;&quot; == false → true (رشته خالی و false هر دو falsy و پس از تبدیل نوع برابرند)
0 == false → true (عدد صفر و false هر دو falsy و پس از تبدیل نوع برابرند)

**پاسخ ۳:

(a &gt;= 18 &amp;&amp; a &lt;= 60) → بررسی بازه ۱۸ تا ۶۰
|| a === 16 → یا دقیقاً برابر ۱۶ باشد
استفاده از === برای مقایسه دقیق


خلاصه نکات مهم:


تفاوت ++x و x++:

x++:
let x = 5;
let y = x++; // y = 5, x = 6

++x:
let x = 5;
let y = ++x; // y = 6, x = 6




تفاوت  و =:

همیشه از === استفاده کن مگر اینکه واقعاً نیاز به تبدیل نوع داشته باشی
== می‌تواند باعث خطاهای غیرمنتظره شود



عملگرهای منطقی:

&amp;&amp; (AND): برای ترکیب چند شرط که همه باید true باشند
|| (OR): برای زمانی که حداقل یکی از شرط‌ها true باشد
! (NOT): برای معکوس کردن مقدار boolean




بخش ۵: کنترل جریان برنامه - تصمیم‌گیری در کد (مطابق متن اصلی)
۱. دستور if
برای اجرای کد در صورت true بودن شرط:
سینتکس:
if (condition) {
    // کدی که اگر شرط true باشد اجرا می‌شود
}
مثال از متن:
let age = 18;
if (age &gt;= 18) {
    console.log(&quot;شما بزرگسال هستید.&quot;);
}
۲. دستور if…else
اگر شرط true باشد یک بلوک، در غیر این صورت بلوک دیگر اجرا می‌شود:
سینتکس:
if (condition) {
    // اگر شرط true باشد
} else {
    // اگر شرط false باشد
}
مثال از متن:
let age_value = 22;
if (age_value &gt;= 18) {
    console.log(&quot;شما بزرگسال هستید.&quot;);
} else {
    console.log(&quot;شما خردسال هستید.&quot;);
}
۳. دستور else if
برای بررسی چندین شرط مختلف:
مثال از متن:
let temperature = 30;
if (temperature &gt; 35) {
    console.log(&quot;روز گرمی است!&quot;);
} else if (temperature &gt; 25) {
    console.log(&quot;روز معتدلی است.&quot;);
} else {
    console.log(&quot;روز خنکی است.&quot;);
}
۴. دستور switch
برای مقایسه یک متغیر با چندین مقدار ثابت:
سینتکس:
switch (expression) {
    case value1:
        // کد اگر expression === value1
        break;
    case value2:
        // کد اگر expression === value2
        break;
    default:
        // کد اگر هیچکدام از caseها مطابقت نکرد
}
مثال از متن:
let fruit = &quot;apple&quot;;
switch (fruit) {
    case &quot;banana&quot;:
        console.log(&quot;میوه زرد&quot;);
        break;
    case &quot;apple&quot;:
        console.log(&quot;میوه قرمز یا سبز&quot;);
        break;
    case &quot;orange&quot;:
        console.log(&quot;میوه نارنجی&quot;);
        break;
    default:
