پروژه تمرینی جامع: برنامه مدیریت وظایف (To-Do List)
این پروژه تمام مباحث یادگرفته شده را پوشش می‌دهد و نیاز به دانش اضافه ندارد.

📋 مشخصات پروژه:
یک برنامه ساده برای مدیریت کارهای روزانه که این قابلیت‌ها را دارد:

افزودن وظیفه جدید
علامت‌زدن وظایف انجام شده
حذف وظایف
نمایش آمار (تعداد کل، انجام شده، باقی مانده)


🎯 مباحث مورد استفاده:

متغیرها (let, const)
انواع داده (String, Number, Boolean, Array, Object)
عملگرها (حساب، مقایسه، منطق)
کنترل جریان (if/else, switch)
حلقه‌ها (for)
توابع (مقدماتی)
مدیریت خطا (try/catch)
دیباگینگ (console.log)


💻 کد کامل پروژه:
&lt;!DOCTYPE html&gt;
&lt;html lang=&quot;fa&quot;&gt;
&lt;head&gt;
    &lt;meta charset=&quot;UTF-8&quot;&gt;
    &lt;title&gt;برنامه مدیریت وظایف&lt;/title&gt;
    &lt;style&gt;
        body { font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px; }
        .task { display: flex; align-items: center; margin: 10px 0; padding: 10px; border: 1px solid #ddd; }
        .completed { text-decoration: line-through; color: #888; }
        button { margin: 0 5px; padding: 5px 10px; cursor: pointer; }
        .stats { background: #f5f5f5; padding: 10px; margin: 10px 0; }
    &lt;/style&gt;
&lt;/head&gt;
&lt;body&gt;
    &lt;h1&gt;📝 برنامه مدیریت وظایف&lt;/h1&gt;

    &lt;div&gt;
        &lt;input type=&quot;text&quot; id=&quot;taskInput&quot; placeholder=&quot;وظیفه جدید را وارد کنید...&quot;&gt;
        &lt;button onclick=&quot;addTask()&quot;&gt;➕ افزودن&lt;/button&gt;
    &lt;/div&gt;

    &lt;div class=&quot;stats&quot; id=&quot;stats&quot;&gt;
        &lt;!-- آمار اینجا نمایش داده می‌شود --&gt;
    &lt;/div&gt;

    &lt;div id=&quot;taskList&quot;&gt;
        &lt;!-- وظایف اینجا نمایش داده می‌شوند --&gt;
    &lt;/div&gt;

    &lt;script&gt;
        // 🔹 بخش ۱: متغیرها و انواع داده
        let tasks = []; // آرایه برای ذخیره وظایف
        const MAX_TASKS = 10; // ثابت برای حداکثر تعداد وظایف

        // 🔹 بخش ۲: توابع اصلی برنامه
        function addTask() {
            try {
                // 🔹 بخش ۳: عملگرها و کنترل جریان
                const taskInput = document.getElementById(&#039;taskInput&#039;);
                const taskText = taskInput.value.trim();

                // اعتبارسنجی ورودی
                if (taskText === &quot;&quot;) {
                    alert(&quot;لطفاً متن وظیفه را وارد کنید!&quot;);
                    return;
                }

                if (tasks.length &gt;= MAX_TASKS) {
                    alert(`حداکثر ${MAX_TASKS} وظیفه مجاز است!`);
                    return;
                }

                // 🔹 بخش ۴: ساختار داده‌ها
                const newTask = {
                    id: Date.now(), // عدد منحصر به فرد
                    text: taskText,
                    completed: false // بولین
                };

                tasks.push(newTask); // افزودن به آرایه
                taskInput.value = &quot;&quot;; // پاک کردن فیلد ورودی

                updateDisplay(); // به‌روزرسانی نمایش
                updateStats(); // به‌روزرسانی آمار

                // 🔹 بخش ۵: دیباگینگ
                console.log(&quot;وظیفه اضافه شد:&quot;, newTask);
                console.log(&quot;تعداد کل وظایف:&quot;, tasks.length);

            } catch (error) {
                // 🔹 بخش ۶: مدیریت خطا
                console.error(&quot;خطا در افزودن وظیفه:&quot;, error);
                alert(&quot;خطایی در افزودن وظیفه رخ داد!&quot;);
            }
        }

        function toggleTask(taskId) {
            // 🔹 بخش ۷: حلقه و جستجو در آرایه
            for (let i = 0; i &lt; tasks.length; i++) {
                if (tasks[i].id === taskId) {
                    tasks[i].completed = !tasks[i].completed; // تغییر وضعیت بولین
                    break; // خروج از حلقه پس از یافتن
                }
            }
            updateDisplay();
            updateStats();
        }

        function deleteTask(taskId) {
            // 🔹 بخش ۸: فیلتر کردن آرایه
            const newTasks = [];
            for (let i = 0; i &lt; tasks.length; i++) {
                if (tasks[i].id !== taskId) {
                    newTasks.push(tasks[i]);
                }
            }
            tasks = newTasks;
            updateDisplay();
            updateStats();
        }

        function updateDisplay() {
            // 🔹 بخش ۹: تولید HTML با حلقه
            const taskList = document.getElementById(&#039;taskList&#039;);
            taskList.innerHTML = &quot;&quot;; // پاک کردن محتوای قبلی

            for (let i = 0; i &lt; tasks.length; i++) {
                const task = tasks[i];

                const taskElement = document.createElement(&#039;div&#039;);
                taskElement.className = `task ${task.completed ? &#039;completed&#039; : &#039;&#039;}`;

                taskElement.innerHTML = `
                    &lt;input type=&quot;checkbox&quot; ${task.completed ? &#039;checked&#039; : &#039;&#039;} 
                           onchange=&quot;toggleTask(${task.id})&quot;&gt;
                    &lt;span style=&quot;flex: 1&quot;&gt;${task.text}&lt;/span&gt;
                    &lt;button onclick=&quot;deleteTask(${task.id})&quot;&gt;🗑️ حذف&lt;/button&gt;
                `;

                taskList.appendChild(taskElement);
            }
        }

        function updateStats() {
            // 🔹 بخش ۱۰: محاسبات و عملگرها
            const totalTasks = tasks.length;
            let completedTasks = 0;

            for (let i = 0; i &lt; tasks.length; i++) {
                if (tasks[i].completed) {
                    completedTasks++;
                }
            }

            const remainingTasks = totalTasks - completedTasks;

            // 🔹 بخش ۱۱: کنترل جریان پیشرفته
            let statusMessage;
            if (totalTasks === 0) {
                statusMessage = &quot;هیچ وظیفه‌ای وجود ندارد!&quot;;
            } else if (completedTasks === totalTasks) {
                statusMessage = &quot;🎉 تمام وظایف انجام شد!&quot;;
            } else {
                statusMessage = `📊 انجام شده: ${completedTasks} | باقی مانده: ${remainingTasks}`;
            }

            const statsElement = document.getElementById(&#039;stats&#039;);
            statsElement.innerHTML = `
                &lt;strong&gt;آمار:&lt;/strong&gt; ${statusMessage}
                ${totalTasks &gt; 0 ? ` | پیشرفت: ${Math.round((completedTasks / totalTasks) * 100)}%` : &#039;&#039;}
            `;
        }

        // 🔹 بخش ۱۲: مقداردهی اولیه
        console.log(&quot;برنامه مدیریت وظایف راه‌اندازی شد!&quot;);

        // اضافه کردن چند وظیفه نمونه
        tasks.push(
            { id: 1, text: &quot;یادگیری جاوااسکریپت&quot;, completed: true },
            { id: 2, text: &quot;انجام پروژه تمرینی&quot;, completed: false }
        );

        updateDisplay();
        updateStats();
    &lt;/script&gt;
&lt;/body&gt;
&lt;/html&gt;

